using Store;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup() => _cart = new ShoppingCart();

    // ── AddItem ──────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_IncreasesTotal()
    {
        _cart.AddItem("SKU-1", 2, 9.99m);

        Assert.AreEqual(19.98m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_SumsCorrectly()
    {
        _cart.AddItem("A", 1, 5.00m);
        _cart.AddItem("B", 3, 2.50m);

        Assert.AreEqual(12.50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantity()
    {
        _cart.AddItem("A", 1, 10.00m);
        _cart.AddItem("A", 2, 10.00m);

        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_NullSku_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem(null!, 1, 1.00m));
    }

    [TestMethod]
    public void AddItem_EmptySku_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.AddItem("", 1, 1.00m));
    }

    [TestMethod]
    public void AddItem_ZeroQuantity_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("A", 0, 1.00m));
    }

    [TestMethod]
    public void AddItem_NegativeQuantity_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("A", -1, 1.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _cart.AddItem("A", 1, -5.00m));
    }

    [TestMethod]
    public void AddItem_ZeroPrice_Succeeds()
    {
        _cart.AddItem("FREE", 1, 0.00m);

        Assert.AreEqual(0.00m, _cart.CalculateTotal());
    }

    // ── RemoveItem ───────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromTotal()
    {
        _cart.AddItem("A", 1, 10.00m);
        _cart.AddItem("B", 1, 5.00m);

        _cart.RemoveItem("A");

        Assert.AreEqual(5.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_OnlyItem_TotalBecomesZero()
    {
        _cart.AddItem("A", 1, 25.00m);

        _cart.RemoveItem("A");

        Assert.AreEqual(0.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsKeyNotFound()
    {
        Assert.ThrowsException<KeyNotFoundException>(
            () => _cart.RemoveItem("MISSING"));
    }

    [TestMethod]
    public void RemoveItem_NullSku_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.RemoveItem(null!));
    }

    [TestMethod]
    public void RemoveItem_AlreadyRemoved_ThrowsKeyNotFound()
    {
        _cart.AddItem("A", 1, 10.00m);
        _cart.RemoveItem("A");

        Assert.ThrowsException<KeyNotFoundException>(
            () => _cart.RemoveItem("A"));
    }

    // ── CalculateTotal ───────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReflectsCurrentState()
    {
        _cart.AddItem("A", 2, 10.00m);
        _cart.AddItem("B", 1, 7.50m);
        _cart.RemoveItem("A");

        Assert.AreEqual(7.50m, _cart.CalculateTotal());
    }

    // ── ApplyCoupon ──────────────────────────────────────────

    [TestMethod]
    public void ApplyCoupon_Save10_Applies10PercentDiscount()
    {
        _cart.AddItem("A", 1, 100.00m);

        _cart.ApplyCoupon("SAVE10");

        Assert.AreEqual(90.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_Save20_Applies20PercentDiscount()
    {
        _cart.AddItem("A", 1, 50.00m);

        _cart.ApplyCoupon("SAVE20");

        Assert.AreEqual(40.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_Half_Applies50PercentDiscount()
    {
        _cart.AddItem("A", 2, 30.00m);

        _cart.ApplyCoupon("HALF");

        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_CaseInsensitive()
    {
        _cart.AddItem("A", 1, 100.00m);

        _cart.ApplyCoupon("save10");

        Assert.AreEqual(90.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    public void ApplyCoupon_NullCode_Throws()
    {
        Assert.ThrowsException<ArgumentException>(
            () => _cart.ApplyCoupon(null!));
    }

    [TestMethod]
    public void ApplyCoupon_ReplacesExistingCoupon()
    {
        _cart.AddItem("A", 1, 100.00m);

        _cart.ApplyCoupon("SAVE10");
        _cart.ApplyCoupon("SAVE20");

        Assert.AreEqual(80.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_OnEmptyCart_TotalRemainsZero()
    {
        _cart.ApplyCoupon("HALF");

        Assert.AreEqual(0.00m, _cart.CalculateTotal());
    }

    // ── Rounding ─────────────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_WithCoupon_RoundsToTwoDecimals()
    {
        _cart.AddItem("A", 3, 9.99m);
        _cart.ApplyCoupon("SAVE10");

        // 29.97 * 0.90 = 26.973 → rounds to 26.97
        Assert.AreEqual(26.97m, _cart.CalculateTotal());
    }
}

